from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# Database connection settings
DB_HOST = 'localhost'
DB_NAME = 'database_name'
DB_USER = 'database_user'
DB_PASSWORD = 'database_password'

def get_db_connection():
    return psycopg2.connect(
        host=DB_HOST,
        database=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        cursor_factory=RealDictCursor
    )

@app.route('/query', methods=['POST'])
def query_database():
    data = request.json

    table_name = data.get('table')
    columns = data.get('columns')
    filters = data.get('filters')

    if not table_name or not columns or not filters:
        return jsonify({'error': 'Missing required parameters'}), 400

    # Sanitize user input
    table_name = psycopg2.sql.Identifier(table_name)
    columns = [psycopg2.sql.Identifier(col) for col in columns]
    filters = {key: value for key, value in filters.items() if value is not None}

    query = """
        SELECT {}
        FROM {}
        WHERE {}
    """.format(
        ', '.join([str(column) for column in columns]),
        str(table_name),
        ' AND '.join(['{} = %s'.format(str(key)) for key in filters.keys()])
    )

    params = [value for value in filters.values()]

    with get_db_connection() as conn:
        cur = conn.cursor()
        cur.execute(query, tuple(params))
        result = cur.fetchall()

    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)